import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { fetchOverviewKPIs, fetchSalesAnalytics, fetchCustomerAnalytics } from "../../features/b2b/adminB2bSlice";
import { Link } from "react-router-dom";
import {
  ArrowLeft, TrendingUp, Package, Users, AlertTriangle, FileText,
  ShieldCheck, CreditCard, Boxes, Clock, DollarSign, BarChart3
} from "lucide-react";

const KpiCard = ({ icon: Icon, label, value, sub, color = "bg-indigo-50 text-indigo-600" }) => (
  <div className="bg-white rounded-3xl border border-slate-100 p-5 shadow-sm">
    <div className="flex items-center gap-3 mb-3">
      <div className={`w-10 h-10 rounded-2xl flex items-center justify-center ${color}`}>
        <Icon size={18} />
      </div>
      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</span>
    </div>
    <span className="text-2xl font-black text-slate-900 block">{value}</span>
    {sub && <span className="text-[11px] font-bold text-slate-400 mt-1 block">{sub}</span>}
  </div>
);

const AdminB2bAnalytics = () => {
  const dispatch = useDispatch();
  const { kpis, salesData, customerAnalytics, isLoading } = useSelector((s) => s.adminB2b);

  useEffect(() => {
    dispatch(fetchOverviewKPIs());
    dispatch(fetchSalesAnalytics({ period: "month" }));
    dispatch(fetchCustomerAnalytics());
  }, [dispatch]);

  const sales = kpis?.sales || {};
  const cust = kpis?.customers || {};
  const rfqs = kpis?.rfqs || {};
  const inv = kpis?.inventory || {};

  return (
    <div className="min-h-screen bg-[#f8fafc]">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-8">
          <Link to="/admin" className="flex items-center gap-1.5 text-sm font-bold text-slate-400 hover:text-indigo-600 mb-2">
            <ArrowLeft size={16} /> Admin Dashboard
          </Link>
          <h1 className="text-2xl font-black text-slate-900">B2B Analytics</h1>
          <p className="text-sm text-slate-500 font-medium mt-1">
            Sales performance, customer insights, and inventory metrics
          </p>
        </div>

        {isLoading && !kpis ? (
          <div className="flex items-center justify-center py-24">
            <div className="w-10 h-10 rounded-full border-2 border-indigo-600 border-t-transparent animate-spin" />
          </div>
        ) : (
          <>
            {/* KPI Cards */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
              <KpiCard icon={DollarSign} label="Total B2B Revenue" value={`${parseFloat(sales.totalRevenue || 0).toLocaleString()} ETB`} color="bg-emerald-50 text-emerald-600" />
              <KpiCard icon={Package} label="Total Orders" value={sales.totalOrders || 0} sub={`${sales.pendingApproval || 0} pending approval`} />
              <KpiCard icon={Users} label="B2B Customers" value={cust.total || 0} sub={`${cust.verified || 0} verified, ${cust.pendingVerification || 0} pending`} color="bg-violet-50 text-violet-600" />
              <KpiCard icon={FileText} label="RFQs" value={rfqs.total || 0} sub={`${rfqs.pending || 0} awaiting response`} color="bg-amber-50 text-amber-600" />
            </div>

            {/* Revenue Metrics */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
              <KpiCard icon={CreditCard} label="Credit Orders" value={sales.creditOrders || 0} sub={`${parseFloat(sales.creditRevenue || 0).toLocaleString()} ETB`} color="bg-blue-50 text-blue-600" />
              <KpiCard icon={AlertTriangle} label="Out of Stock" value={inv.outOfStock || 0} color="bg-rose-50 text-rose-600" />
              <KpiCard icon={Clock} label="Expiring Soon" value={inv.expiringSoon || 0} sub={`${inv.alreadyExpired || 0} already expired`} color="bg-orange-50 text-orange-600" />
              <KpiCard icon={Boxes} label="Low Stock" value={inv.lowStock || 0} color="bg-amber-50 text-amber-600" />
            </div>

            {/* Sales Trends */}
            {salesData?.salesTrend?.length > 0 && (
              <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm mb-8">
                <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5 flex items-center gap-2">
                  <BarChart3 size={16} /> Monthly Sales Trend
                </h3>
                <div className="overflow-x-auto">
                  <div className="flex items-end gap-2 min-w-[600px] h-48">
                    {salesData.salesTrend.map((item, i) => {
                      const maxRev = Math.max(...salesData.salesTrend.map((t) => t.revenue || 1));
                      const height = Math.max(8, (item.revenue / maxRev) * 160);
                      const month = new Date(item.timePeriod).toLocaleDateString("en-US", { month: "short", year: "2-digit" });
                      return (
                        <div key={i} className="flex flex-col items-center flex-1 gap-1">
                          <span className="text-[9px] font-black text-slate-500">
                            {item.revenue?.toLocaleString()}
                          </span>
                          <div
                            className="w-full bg-gradient-to-t from-indigo-600 to-violet-500 rounded-t-lg transition-all"
                            style={{ height: `${height}px` }}
                          />
                          <span className="text-[9px] font-bold text-slate-400">{month}</span>
                          <span className="text-[8px] font-bold text-slate-300">{item.ordersCount} orders</span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            )}

            {/* Category Sales + Top Buyers Side by Side */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Category Sales */}
              {salesData?.categorySales?.length > 0 && (
                <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm">
                  <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5 flex items-center gap-2">
                    <TrendingUp size={16} /> Sales by Category
                  </h3>
                  <div className="space-y-3">
                    {salesData.categorySales.map((cat, i) => {
                      const maxRev = Math.max(...salesData.categorySales.map((c) => c.revenue || 1));
                      const pct = (cat.revenue / maxRev) * 100;
                      return (
                        <div key={i}>
                          <div className="flex justify-between text-xs font-bold text-slate-600 mb-1">
                            <span className="capitalize">{cat.category.replace(/_/g, " ").toLowerCase()}</span>
                            <span>{cat.revenue.toLocaleString()} ETB</span>
                          </div>
                          <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                            <div className="h-full bg-gradient-to-r from-indigo-500 to-violet-500 rounded-full transition-all" style={{ width: `${pct}%` }} />
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Top Buyers */}
              {customerAnalytics?.topBuyers?.length > 0 && (
                <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm">
                  <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5 flex items-center gap-2">
                    <Users size={16} /> Top B2B Buyers
                  </h3>
                  <div className="space-y-3">
                    {customerAnalytics.topBuyers.map((buyer, i) => (
                      <div key={buyer.id} className="flex items-center gap-3 p-3 bg-slate-50 rounded-2xl">
                        <span className="w-7 h-7 bg-indigo-100 text-indigo-700 rounded-xl flex items-center justify-center text-xs font-black">
                          {i + 1}
                        </span>
                        <div className="flex-1 min-w-0">
                          <span className="font-extrabold text-sm text-slate-800 block truncate">
                            {buyer.institutionName || `${buyer.firstname} ${buyer.lastname}`}
                          </span>
                          <span className="text-[10px] text-slate-400 font-bold">
                            {buyer.ordersCount} orders • {buyer.customerType?.replace(/_/g, " ")}
                          </span>
                        </div>
                        <span className="text-sm font-black text-slate-900 flex-shrink-0">
                          {buyer.totalSpend.toLocaleString()} <span className="text-[10px] text-slate-400">ETB</span>
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Customer Type Breakdown */}
              {customerAnalytics?.customerTypes?.length > 0 && (
                <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm">
                  <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-5 flex items-center gap-2">
                    <ShieldCheck size={16} /> Customer Types
                  </h3>
                  <div className="space-y-3">
                    {customerAnalytics.customerTypes.map((type, i) => (
                      <div key={i} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl">
                        <div>
                          <span className="font-extrabold text-sm text-slate-800 capitalize block">
                            {type.customerType.replace(/_/g, " ").toLowerCase()}
                          </span>
                          <span className="text-[10px] text-slate-400 font-bold">
                            {type.verifiedCount} verified of {type.count}
                          </span>
                        </div>
                        <span className="text-lg font-black text-slate-900">{type.count}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Quick Nav */}
            <div className="mt-8 flex flex-wrap gap-3">
              <Link to="/admin/b2b/orders" className="px-5 py-2.5 bg-indigo-600 text-white rounded-2xl text-sm font-bold hover:bg-indigo-700 transition-colors">
                Manage Orders →
              </Link>
              <Link to="/admin/b2b/customers" className="px-5 py-2.5 bg-violet-600 text-white rounded-2xl text-sm font-bold hover:bg-violet-700 transition-colors">
                Manage Customers →
              </Link>
              <Link to="/admin/b2b/rfqs" className="px-5 py-2.5 bg-amber-600 text-white rounded-2xl text-sm font-bold hover:bg-amber-700 transition-colors">
                Manage RFQs →
              </Link>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default AdminB2bAnalytics;
